import React, { useState, useRef } from 'react';
import { enhanceCV, enhanceCVFromImage } from '../services/geminiService';

interface CVEnhancerProps {
  targetJob: string;
}

const CVEnhancer: React.FC<CVEnhancerProps> = ({ targetJob }) => {
  const [currentCV, setCurrentCV] = useState('');
  const [enhancedCV, setEnhancedCV] = useState('');
  const [loading, setLoading] = useState(false);
  const [inputMode, setInputMode] = useState<'text' | 'image'>('text');
  const [imagePreview, setImagePreview] = useState<string | null>(null);
  const [imageData, setImageData] = useState<{ base64: string; mimeType: string } | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        const base64String = (reader.result as string).split(',')[1];
        setImagePreview(reader.result as string);
        setImageData({ base64: base64String, mimeType: file.type });
      };
      reader.readAsDataURL(file);
    }
  };

  const handleEnhance = async () => {
    setLoading(true);
    try {
      let result = '';
      if (inputMode === 'text' && currentCV.trim()) {
        result = await enhanceCV(currentCV, targetJob) || '';
      } else if (inputMode === 'image' && imageData) {
        result = await enhanceCVFromImage(imageData.base64, imageData.mimeType, targetJob) || '';
      }
      setEnhancedCV(result || "No response generated. Please try again.");
    } catch (error) {
      console.error(error);
      setEnhancedCV("Error enhancing CV. Please check your connection.");
    } finally {
      setLoading(false);
    }
  };

  const resetImage = () => {
    setImagePreview(null);
    setImageData(null);
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  return (
    <div className="space-y-8">
      <div>
        <h2 className="text-3xl font-bold text-gray-900">AI CV Enhancer</h2>
        <p className="text-gray-500 mt-2">
          Tailoring your resume for: <span className="font-semibold text-brand-600">{targetJob || 'Your Future Career'}</span>
        </p>
      </div>

      <div className="grid md:grid-cols-2 gap-8 items-start">
        {/* Input Side */}
        <div className="flex flex-col h-full bg-white p-6 rounded-2xl border border-gray-100 shadow-sm">
          <div className="flex bg-gray-100 p-1 rounded-lg mb-6 self-start">
            <button
              onClick={() => setInputMode('text')}
              className={`px-4 py-2 rounded-md text-sm font-medium transition-all ${inputMode === 'text' ? 'bg-white text-brand-700 shadow-sm' : 'text-gray-500 hover:text-gray-700'}`}
            >
              Paste Text
            </button>
            <button
              onClick={() => setInputMode('image')}
              className={`px-4 py-2 rounded-md text-sm font-medium transition-all ${inputMode === 'image' ? 'bg-white text-brand-700 shadow-sm' : 'text-gray-500 hover:text-gray-700'}`}
            >
              Upload Image
            </button>
          </div>

          <div className="flex-1 min-h-[350px]">
            {inputMode === 'text' ? (
              <textarea
                className="w-full h-full p-4 rounded-xl border-gray-200 border focus:ring-2 focus:ring-brand-500 focus:border-transparent outline-none shadow-inner resize-none font-mono text-sm bg-gray-50"
                placeholder="Paste your current resume text here..."
                value={currentCV}
                onChange={(e) => setCurrentCV(e.target.value)}
              />
            ) : (
              <div className="h-full flex flex-col">
                {!imagePreview ? (
                  <div 
                    onClick={() => fileInputRef.current?.click()}
                    className="flex-1 border-2 border-dashed border-gray-200 rounded-xl flex flex-col items-center justify-center p-8 cursor-pointer hover:border-brand-400 hover:bg-brand-50 transition-all bg-gray-50"
                  >
                    <div className="w-16 h-16 bg-white rounded-full flex items-center justify-center shadow-sm mb-4">
                      <svg className="w-8 h-8 text-brand-500" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" />
                      </svg>
                    </div>
                    <p className="text-gray-700 font-bold">Select CV Image</p>
                    <p className="text-gray-400 text-sm mt-1">PNG, JPG or JPEG up to 10MB</p>
                    <input 
                      type="file" 
                      className="hidden" 
                      accept="image/*"
                      ref={fileInputRef}
                      onChange={handleFileChange}
                    />
                  </div>
                ) : (
                  <div className="relative flex-1 group rounded-xl overflow-hidden border border-gray-200 shadow-sm bg-gray-100">
                    <img src={imagePreview} alt="CV Preview" className="w-full h-full object-contain" />
                    <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center gap-4">
                       <button 
                         onClick={() => fileInputRef.current?.click()}
                         className="bg-white p-2 rounded-full text-brand-600 hover:scale-110 transition-transform shadow-lg"
                       >
                         <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z" /></svg>
                       </button>
                       <button 
                         onClick={resetImage}
                         className="bg-white p-2 rounded-full text-red-600 hover:scale-110 transition-transform shadow-lg"
                       >
                         <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
                       </button>
                    </div>
                  </div>
                )}
              </div>
            )}
          </div>

          <button
            onClick={handleEnhance}
            disabled={loading || (inputMode === 'text' && !currentCV) || (inputMode === 'image' && !imageData)}
            className="mt-6 w-full bg-brand-600 text-white py-4 rounded-xl font-bold hover:bg-brand-700 disabled:opacity-50 transition-all shadow-lg hover:shadow-xl flex justify-center items-center gap-2 active:scale-95"
          >
            {loading ? (
              <>
                <svg className="animate-spin h-5 w-5 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                  <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                  <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                </svg>
                Processing with Gemini...
              </>
            ) : (
              <>
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 10V3L4 14h7v7l9-11h-7z" /></svg>
                Enhance with AI
              </>
            )}
          </button>
        </div>

        {/* Output Side */}
        <div className="flex flex-col h-full bg-white p-6 rounded-2xl border border-gray-100 shadow-sm">
          <label className="block text-sm font-bold text-gray-700 mb-4 uppercase tracking-wider">Optimized Version</label>
          <div className="flex-1 w-full min-h-[445px] p-6 rounded-xl border border-gray-100 bg-gray-50 overflow-y-auto">
            {enhancedCV ? (
              <div className="prose prose-sm prose-blue max-w-none whitespace-pre-wrap leading-relaxed">
                {enhancedCV}
              </div>
            ) : (
              <div className="h-full flex flex-col items-center justify-center text-gray-400 text-center p-8 space-y-4">
                 <div className="w-16 h-16 bg-gray-100 rounded-full flex items-center justify-center">
                    <svg className="w-8 h-8 opacity-20" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" /></svg>
                 </div>
                 <p className="font-medium">Your enhanced, professional CV will appear here once processed.</p>
              </div>
            )}
          </div>
          {enhancedCV && (
             <button
               onClick={() => navigator.clipboard.writeText(enhancedCV)}
               className="mt-6 w-full bg-white text-gray-700 border border-gray-200 py-4 rounded-xl font-bold hover:bg-gray-50 transition-all shadow-sm active:scale-95"
             >
               Copy to Clipboard
             </button>
