 * to prevent conflicts with pre-existing global declarations in the environment.
 */
declare global {
  interface Window {
    aistudio: {
      hasSelectedApiKey(): Promise<boolean>;
      openSelectKey(): Promise<void>;
    };
  }
}

interface CVEnhancerProps {
  targetJob: string;
}

