                  </div>
                  <div className="flex flex-col gap-3 shrink-0">
                    <button className="bg-brand-600 text-white px-10 py-4 rounded-2xl font-black hover:bg-brand-700 transition-all shadow-xl shadow-brand-100 active:scale-95">
                      Apply Now
